// Build Model Usage Rows
// Mode: Run Once for All Items
// Emits one row per agent that exists in the CALLING workflow, with status
// indicating execution state. We do NOT pad with agents from other workflows
// (a refinement run never emits discovery/application-only agents).
const jobResult = $input.first().json.job_result || {};
const generatedAt = new Date().toISOString();

// Run identity precedence: this-run's own run_id FIRST, application_run_id only
// as a fallback for the application path (which sets application_run_id but no
// top-level run_id). Refinement sets run_id='refine_*' AND application_run_id=
// 'app_*' (an FK to the parent run) â€” reading application_run_id first here
// mis-detected refinement runs as application runs. run_id is this run's identity.
const runId = jobResult.run_id || jobResult.application_run_id || '';
const runType = runId.startsWith('app_') ? 'application' :
                runId.startsWith('disc_') ? 'discovery' :
                runId.startsWith('refine_') ? 'refinement' :
                runId.startsWith('cl_') ? 'cover_letter' : 'unknown';

// job_id: present on application + refinement runs. Blank by design on discovery
// (scoring happens before job_id is minted in Build Discovery Row).
const jobId = (runType === 'discovery') ? '' : (jobResult.job?.job_id || '');

let agents = [];

if (runType === 'application') {
  agents = [
    { name: 'agent_1', sub: jobResult.resume },
    { name: 'agent_2', sub: jobResult.cover_letter },
    { name: 'agent_3', sub: jobResult.verifier },
    { name: 'agent_4', sub: jobResult.cover_verifier },
    { name: 'agent_5', sub: jobResult.critic },
    { name: 'agent_7', sub: jobResult.scorer }
  ];
} else if (runType === 'refinement') {
  // Refiner workflow. Polish â†’ Agent 6; Refine â†’ Agent 9. Plus optional verifier + scorer.
  const refinerAgent = (jobResult.mode === 'polish') ? 'agent_6' : 'agent_9';
  agents = [
    { name: refinerAgent, sub: jobResult.refiner },
    { name: 'agent_3', sub: jobResult.verifier },
    { name: 'agent_7', sub: jobResult.scorer }
  ];
} else if (runType === 'discovery') {
  // jobResult here is the wrapper built by Job_Discovery's Model Usage Recorder
  // input mapping: { scored_jobs: [...], agent_10_usage: {...}|null, run_id }.
  //
  // Agent 10 (Job Ranker) â€” one row per run, regardless of result count.
  agents.push({ name: 'agent_10', sub: jobResult.agent_10_usage || null });

  // Agent 8 (Discovery Scorer) â€” one row per scored job. On the false branch
  // (zero jobs through the ranker), scored_jobs is [] and we emit one
  // "disabled" agent_8 row so every run has a complete agent picture.
  // Each scored_job carries model_used / tokens / cost at the top level,
  // already matching the shape classify/buildRow expect.
  const a8List = Array.isArray(jobResult.scored_jobs) ? jobResult.scored_jobs : [];
  if (a8List.length === 0) {
    agents.push({ name: 'agent_8', sub: null });
  } else {
    for (const s of a8List) agents.push({ name: 'agent_8', sub: s });
  }
} else if (runType === 'cover_letter') {
  // Cover Letter Generation/Refinement workflow.
  // Generate â†’ Agent 2; Refine â†’ Agent 11. Plus optional verifier (Agent 4).
  const buildAgent = (jobResult.mode === 'generate') ? 'agent_2' : 'agent_11';
  agents = [
    { name: buildAgent, sub: jobResult.cover_letter },
    { name: 'agent_4', sub: jobResult.cover_verifier }
  ];
} else {
  throw new Error(`[Model Usage Recorder] Unknown run_id prefix â€” cannot classify run '${runId}'. Expected app_/disc_/refine_/cl_.`);
}

const classify = (sub) => {
  if (!sub) return 'disabled';
  // Agents with an explicit `ran` flag â€” honor it
  if (sub.ran === false) return 'disabled';
  if (sub.cascaded === true) return 'cascaded';
  const m = sub.model_used;
  if (!m || m === 'skipped' || m === 'crash' || m === 'unknown') return 'failed';
  return 'ran';
};

const rows = [];
for (const a of agents) {
  const status = classify(a.sub);
  const model = (status === 'ran') ? a.sub.model_used : '';
  const provider = (status === 'ran') ? (a.sub.provider_used || '') : '';
  // Preserve tokens/cost on ALL non-disabled statuses.
  // Cascade and failed runs still burn tokens before the decision.
  const tokensIn   = (status === 'disabled') ? 0 : (a.sub?.tokens?.input || 0);
  const tokensOut  = (status === 'disabled') ? 0 : (a.sub?.tokens?.output || 0);
  const cachedIn   = (status === 'disabled') ? 0 : (a.sub?.cached_input_tokens || 0);
  const cacheWrite = (status === 'disabled') ? 0 : (a.sub?.cache_write_tokens || 0);
  const costUsd    = (status === 'disabled') ? 0 : Number((a.sub?.cost || 0).toFixed(6));
  rows.push({
    json: {
      run_id: runId,
      job_id: jobId,
      agent_name: a.name,
      status,
      provider,
      model_used: model,
      generated_at: generatedAt,
      tokens_in: tokensIn,
      tokens_out: tokensOut,
      cached_input_tokens: cachedIn,
      cache_write_tokens: cacheWrite,
      cost_usd: costUsd
    }
  });
}

console.log(`[Model Usage Recorder] run_id=${runId}, job_id=${jobId || '(none)'}, run_type=${runType}, emitting ${rows.length} row(s): ${rows.map(r => r.json.agent_name + '=' + r.json.status).join(', ')}`);

return rows;
